const input = $input.first().json;
const body = input.body || input;

if (body.source !== 'google_apps_script') {
  throw new Error('Unauthorized source');
}

const event = body.event || {};
const event_id = String(event.id || '').substring(0, 255);
if (!event_id) throw new Error('Missing event.id');

return [{ json: {
  event_id,
  status: String(event.status || 'unknown').toLowerCase(),
  calendar_id: String(body.calendar_id || 'unknown').substring(0, 255),
  _is_cancelled: event.status === 'cancelled'
}}];

const input = $input.first().json;
const wasCancelled = !!input.id;
return [{ json: { action: wasCancelled ? 'booking_cancelled' : 'no_booking_found', booking_id: input.id || null, error: input.message || null } }];

const input = $input.first().json;
const wasUpdated = !!input.id;
return [{ json: { action: wasUpdated ? 'sync_updated' : 'no_booking_found', booking_id: input.id || null, error: input.message || null } }];

const input = $input.first().json;
const webhookData = $('Validate & Extract').first().json;
const hasError = !!input.error;

return [{ json: {
  success: !hasError,
  data: {
    updated: input.action !== 'no_booking_found' && !hasError,
    booking_id: input.booking_id,
    action_taken: input.action,
    event_id: webhookData.event_id,
    error: input.error
  },
  _meta: {
    source: 'WF4_Sync_Engine_Event_Driven',
    timestamp: new Date().toISOString(),
    workflow_id: $workflow.id
  }
}}];
